# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import os
import pymysql

def lambda_handler(event, context):
    # Database connection details from environment variables
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')

    if not all([db_host, db_user, db_password, db_name]):
        return {
            'statusCode': 500,
            'body': json.dumps('Database connection details are missing. Check environment variables.')
        }

    conn = None
    try:
        conn = pymysql.connect(
            host=db_host,
            user=db_user,
            passwd=db_password,
            db=db_name,
            connect_timeout=5
        )
        cursor = conn.cursor(pymysql.cursors.DictCursor)

        # Parse search parameters from the API Gateway event
        # Assuming parameters are in event['queryStringParameters'] for GET requests
        # or event['body'] for POST requests (which would need json.loads)
        search_params = event.get('queryStringParameters', {})
        if not search_params and event.get('body'):
            try:
                search_params = json.loads(event['body'])
            except json.JSONDecodeError:
                return {
                    'statusCode': 400,
                    'body': json.dumps('Invalid JSON in request body.')
                }

        # Build SQL query dynamically
        base_sql = "SELECT id, name, description, price, category, stock_quantity FROM products"
        conditions = []
        sql_params = []

        if 'name' in search_params and search_params['name']:
            conditions.append("name LIKE %s")
            sql_params.append(f"%{search_params['name']}%")
        if 'category' in search_params and search_params['category']:
            conditions.append("category = %s")
            sql_params.append(search_params['category'])
        if 'min_price' in search_params and search_params['min_price']:
            try:
                min_price = float(search_params['min_price'])
                conditions.append("price >= %s")
                sql_params.append(min_price)
            except ValueError:
                pass # Ignore invalid price
        if 'max_price' in search_params and search_params['max_price']:
            try:
                max_price = float(search_params['max_price'])
                conditions.append("price <= %s")
                sql_params.append(max_price)
            except ValueError:
                pass # Ignore invalid price
        if 'description' in search_params and search_params['description']:
            conditions.append("description LIKE %s")
            sql_params.append(f"%{search_params['description']}%")
        if 'min_stock' in search_params and search_params['min_stock']:
            try:
                min_stock = int(search_params['min_stock'])
                conditions.append("stock_quantity >= %s")
                sql_params.append(min_stock)
            except ValueError:
                pass # Ignore invalid stock

        if conditions:
            sql_query = base_sql + " WHERE " + " AND ".join(conditions)
        else:
            sql_query = base_sql

        # Add limit and offset for pagination (optional)
        limit = int(search_params.get('limit', 10))
        offset = int(search_params.get('offset', 0))
        sql_query += " LIMIT %s OFFSET %s"
        sql_params.extend([limit, offset])

        cursor.execute(sql_query, tuple(sql_params))
        products = cursor.fetchall()

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps(products)
        }

    except pymysql.MySQLError as e:
        print(f"Database error: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f"Database error: {e}")
        }
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f"An unexpected error occurred: {e}")
        }
    finally:
        if conn:
            conn.close()